var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`다른 사람이 제게 이런 제안을 했다면 경찰을 매수하려 한 죄로 수갑부터 꺼냈겠지만......`,JPN:`もし他の人からの提案だったら、警官を買収しようとした容疑で手錠をかけてるところですけど……`,ENG:` If anyone else made me this offer, I would've handcuffed them for attempting to bribe a police officer.`,TWN:`如果是別人向我這樣提案，我會以試圖賄賂警察的罪名，給他戴上手銬的......`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`사장님에게 그런 말을 들으니 마음이 싱숭생숭하네요.`,JPN:`社長からそんなことを言われるなんて、何だかソワソワしちゃいますね。`,ENG:` But I don't know what to do with you.`,TWN:`但聽到老闆這麼說，我還真有些心慌意亂呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`이건 마치, 관심 있던 남자애한테 고백을 받은 기분인데요?`,JPN:`これって、まるで気になっていた男子から告白されたときの気分かも？`,ENG:` I feel as if... I've been asked out by someone I like.`,TWN:`就像是，被喜歡的男孩子告白的感覺？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`하하, 농담이에요.`,JPN:`あはっ、ジョーダン、ジョーダンですって。`,ENG:` Hah hah. I was just kidding.`,TWN:`哈哈，開玩笑的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`사실 그런 고백 같은 거, 전엔 받아본 적도 없고......`,JPN:`実は告白なんか、されたことないですしね……`,ENG:` Actually, I wouldn't know what it feels like, since I've never been asked out...`,TWN:`其實我從來沒有收過那種告白......`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`뭐 아무튼!`,JPN:`まあ、とにかく！`,ENG:` ANYWAY!`,TWN:`但總而言之！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SOYEONG_POLICE_NULL_NULL`,text:{KOREA:`이젠 뗄래야 뗄 수 없는 관계가 되었으니 앞으로 부탁드릴게요.`,JPN:`もう切っても切れない仲になったんですから、これからもよろしくお願いしますね。`,ENG:` Now, you can't get rid of me even if you want to.`,TWN:`我們已經是切也切不斷的關係了，以後就請多多指教囉。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOYEONG_POLICE_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}}];export{e as default};